member.example:
Bind the TMP_Text alignment using a serialized binder field.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TextAlignmentBinder _alignment;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TextAlignmentOptions _alignment;
    }


Bind the TMP_Text alignment by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _target;
        
        private TextAlignmentBinder Alignment =>
            new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TextAlignmentOptions _alignment;
    }

Switch the TMP_Text alignment between two values using a serialized binder field.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TextAlignmentSwitcherBinder _isCentered;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isCentered;
    }


Switch the TMP_Text alignment between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _target;
        
        private TextAlignmentSwitcherBinder IsCentered => new(
            _target, TextAlignmentOptions.Center, TextAlignmentOptions.Left);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isCentered;
    }
